  function ownerId(){if(session.role==="admin")return(session.adminMode==="company"?session.companyOwnerId:session._linkedCoId)||session.id;if(session.companyOwnerId)return session.companyOwnerId;const stored=users.find(u=>cleanId(u.id)===cleanId(session.id));return stored?.companyOwnerId||session.id}
  function recOwner(r){return r?.companyOwnerId||r?.createdBy||r?.linkedBy||"platform"}
