  function signatureArea(x,companyOwnerId){const co=companyOwnerId?ownerCompanies.find(c=>c.ownerId===companyOwnerId||c.id===companyOwnerId||c.ownerIds?.includes(companyOwnerId)):activeOwnerCompany();const party1=co?.name||"المنشأة";const party2=x?.clientCompanyName||x?.clientName||partyLabel(x)||contractLabel(x)||"الطرف الثاني";const stampData=(window.__appBridge?.companyStamp?.())||"";const stampHtml=stampData?`<img src="${stampData}" style="max-width:100%;max-height:85px;object-fit:contain" alt="ختم">`:`<div style="min-height:50px;margin-top:6px;border:1px dashed #dfe8e4;border-radius:6px;background:#fff"></div>`;return `<div class="signature-grid" style="display:grid;grid-template-columns:1fr 1fr;gap:16px;padding:16px 20px;break-inside:avoid;page-break-inside:avoid;margin-top:12px"><section style="border:1.5px solid #c5d9cf;border-radius:12px;padding:16px;min-height:130px;background:linear-gradient(135deg,#f8fbf9,#f0f6f3)"><h4 style="margin:0 0 6px;color:#0d312f;font-size:11px;font-weight:900;border-bottom:2px solid #d4a24e;padding-bottom:4px">الطرف الأول</h4><p style="margin:4px 0 2px;font-size:13px;font-weight:700;color:#0d312f">${esc(party1)}</p><small style="color:#6b7f7a;font-size:9px">التوقيع / الختم</small>${stampHtml}</section><section style="border:1.5px solid #c5d9cf;border-radius:12px;padding:16px;min-height:130px;background:linear-gradient(135deg,#f8fbf9,#f0f6f3)"><h4 style="margin:0 0 6px;color:#0d312f;font-size:11px;font-weight:900;border-bottom:2px solid #d4a24e;padding-bottom:4px">الطرف الثاني</h4><p style="margin:4px 0 2px;font-size:13px;font-weight:700;color:#0d312f">${esc(party2)}</p><small style="color:#6b7f7a;font-size:9px">التوقيع / الختم</small><div style="min-height:50px;margin-top:6px;border:1px dashed #dfe8e4;border-radius:6px;background:#fff"></div></section></div>`}
