  window.voiceRecordSample=function(){const btn=$("#voiceRecordBtn");if(!btn)return;btn.disabled=true;btn.textContent="⏺ التسجيل...";let stream=null,ctx=null,source=null,processor=null,chunks=[];navigator.mediaDevices.getUserMedia({audio:true}).then(s=>{stream=s;ctx=new(window.AudioContext||window.webkitAudioContext)();source=ctx.createMediaStreamSource(stream);processor=ctx.createScriptProcessor(4096,1,1);processor.onaudioprocess=e=>chunks.push(new Float32Array(e.inputBuffer.getChannelData(0)));source.connect(processor);processor.connect(ctx.destination);setTimeout(()=>{try{processor.disconnect();source.disconnect();stream.getTracks().forEach(t=>t.stop())}catch{}const blob=voiceEncodeWav(chunks,ctx.sampleRate);try{ctx.close()}catch{}const reader=new FileReader();reader.onloadend=function(){const base64=reader.result.split(",")[1];fetch("/api/voice/samples/upload",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({audio:base64,name:"sample_"+Date.now()+".wav"})}).then(r=>r.json()).then(d=>{toast(d.message||"تم رفع العينة");voiceSettingsPage()}).catch(()=>toast("تعذر رفع العينة")).finally(()=>{btn.disabled=false;btn.textContent="🎙 تسجيل عينة (5 ثوان)"})};reader.readAsDataURL(blob)},5000)}).catch(err=>{toast("تعذر الوصول للميكروفون: "+err.message);btn.disabled=false;btn.textContent="🎙 تسجيل عينة (5 ثوان)"})};
