  function technicalSpecsFields(info={}){return `<section class="contract-spec-editor"><div class="contract-tabs">${specGroups.map((g,i)=>`<button type="button" class="contract-tab ${i?"":"active"}" data-contract-tab="${i}">${g.tab}</button>`).join("")}</div>${specGroups.map((g,i)=>`<fieldset class="item-picker contract-tab-panel ${i?"":"active"}" data-contract-tab-panel="${i}"><legend>${g.tab}</legend><div class="form-grid spec-grid">${g.fields.map(([k,l,t,opts])=>{const v=specValue(info,k);return t==="select"?specSelect(k,l,opts,v):t==="textarea"?`<label class="wide">${l}<textarea name="spec_${k}">${esc(v)}</textarea></label>`:`<label>${l}<input name="spec_${k}" value="${esc(v)}"></label>`}).join("")}</div></fieldset>`).join("")}</section>`}
  const collectTechnicalSpecs=f=>{const els=typeof f?.querySelectorAll==="function"?$$("[name^='spec_']",f):Array.from(f||[]).filter(el=>el.name&&el.name.startsWith("spec_"));return Object.assign({},specDefaults,...els.map(el=>({[el.name.replace(/^spec_/,"")]:el.value})))};
  const elevatorFields=(info={})=>technicalSpecsFields(info);
  const collectElevator=f=>{const specs=collectTechnicalSpecs(f);return Object.assign({count:"1",brand:specs.motorManufacturer||"",age:specs.stops||"",capacity:specs.capacity||"",doorType:specs.doorType||"",usage:specs.usage||""},specs)};
  const collectContractElevator=(f,old={})=>collectElevator(f.elements||f);
  function installationFields(i={}){return `<fieldset class="item-picker installation-fields"><legend>مواصفات عقد التركيب حسب النموذج</legend><div class="form-grid"><label>عدد الوقفات<input name="installStops" type="number" min="1" value="${esc(i.stops)}"></label><label>عدد المداخل<input name="installEntrances" type="number" min="1" value="${esc(i.entrances)}"></label><label>البطارية<select name="installBattery"><option></option><option ${i.battery==="نعم"?"selected":""}>نعم</option><option ${i.battery==="لا"?"selected":""}>لا</option></select></label><label>السرعة<input name="installSpeed" value="${esc(i.speed)}" placeholder="مثال: 1m/s"></label><label>فتحة الباب<input name="installDoorOpening" value="${esc(i.doorOpening)}" placeholder="مثال: 80 سم"></label><label>أبعاد البئر<input name="installShaftSize" value="${esc(i.shaftSize)}" placeholder="مثال: 2.50 × 2.30"></label><label>المكينة<input name="installMotor" value="${esc(i.motor)}" placeholder="مثال: إيطالي"></label><label>الكنترول<input name="installController" value="${esc(i.controller)}" placeholder="مثال: VEGA"></label><label>الأبواب الخارجية<input name="installOuterDoors" value="${esc(i.outerDoors)}"></label><label>باب الأمان الداخلي<input name="installSafetyDoor" value="${esc(i.safetyDoor)}"></label><label>الكابينة<input name="installCabin" value="${esc(i.cabin)}" placeholder="استانلس، مرايا، أرضية..."></label><label>نظام الكهرباء<input name="installPower" value="${esc(i.power)}" placeholder="3 Phase 380v"></label><label>الضمان<input name="installWarranty" value="${esc(i.warranty)}" placeholder="مثال: سنة"></label></div><label>ملاحظة العرض<textarea name="installNote">${esc(i.note)}</textarea></label></fieldset>`}
  const collectInstallation=f=>({stops:f.installStops?.value||"",entrances:f.installEntrances?.value||"",battery:f.installBattery?.value||"",doorOpening:f.installDoorOpening?.value||"",shaftSize:f.installShaftSize?.value||"",motor:f.installMotor?.value||"",controller:f.installController?.value||"",outerDoors:f.installOuterDoors?.value||"",safetyDoor:f.installSafetyDoor?.value||"",cabin:f.installCabin?.value||"",power:f.installPower?.value||"",speed:f.installSpeed?.value||"",warranty:f.installWarranty?.value||"",note:f.installNote?.value||"",installDuration:f.installDuration?.value||"",maintenancePeriod:f.installMaintenancePeriod?.value||""});
  function maintenanceClauses(){return `<section class="contract-section"><h3>خامساً: الضمان على أعمال الصيانة</h3><div class="contract-terms"><article><p>تتحمل الشركة المصنعة أو الموردة أو الشركة المنفذة لأعمال الصيانة (الطرف الأول) مسؤولية ضمان أعمال الصيانة التي تقوم بها وتكون مسؤولة عن أي عيوب أو أخطاء في تلك الأعمال.</p></article><article><p>يكون الضمان ساري المفعول لمدة عام من تاريخ بداية العقد على الأجزاء التي تمت صيانتها أو استبدالها في حالة الصيانة الناتجة عن سوء التركيب أو التصنيع أو عدم سلامة التصنيع.</p></article><article><p>مدة الضمان لعملية الصيانة تكون عاماً من تاريخ التنفيذ، وفي حال وجود أي عيوب في أعمال الصيانة يجب على الطرف الأول إعادة الصيانة أو إصلاح العيوب خلال مدة لا تتجاوز خمسة عشر يوماً من تاريخ الإشعار وبما لا يخل بضمان أعمال الصيانة.</p></article><article><p>في حالة وجود أي عيوب أو أخطاء في الصيانة من وجهة نظر الطرف الثاني، عليه إخطار الطرف الأول بذلك ويجب أن يتضمن الإخطار وصفاً كاملاً للعيوب أو الأخطاء.</p></article></div></section><section class="contract-section"><h3>سادساً: التزامات الطرف الثاني</h3><div class="contract-terms"><article><p>يلتزم الطرف الثاني بتوفير متطلبات السلامة لحماية العاملين في الموقع، وتوفير مساحة عمل آمنة ومناسبة لفريق الصيانة، مع توفير الإضاءة والطاقة الكهربائية اللازمة لتنفيذ أعمالهم بأمان وسلامة.</p></article><article><p>إخلاء مسؤولية الطرف الأول عن أي حوادث أو إصابات أو أضرار تلحق بالغير أو بالعاملين في الموقع نتيجة إهمال الطرف الثاني أو عدم توفير بيئة عمل آمنة.</p></article><article><p>يلتزم الطرف الثاني بإبلاغ الطرف الأول فوراً في حال حدوث أي عطل مفاجئ في المصعد.</p></article><article><p>في حال عدم قيام الطرف الثاني بالتزاماته، يحق للطرف الأول تعليق الخدمة حتى يتم الالتزام.</p></article></div></section><section class="contract-section"><h3>سابعاً: المسؤولية والسلامة</h3><div class="contract-terms"><article><p>يكون الطرف الأول مسؤولاً عن سلامة تنفيذ أعمال الصيانة وفقاً لأصول المهنة والشروط المتفق عليها.</p></article><article><p>يكون الطرف الثاني مسؤولاً عن سلامة الموقع وتوفير بيئة عمل آمنة وفقاً للوائح وأنظمة السلامة المهنية.</p></article><article><p>يكون الطرف الأول مسؤولاً عن سلامة وأداء المصعد (المصاعد) بعد الصيانة.</p></article></div></section><section class="contract-section"><h3>ثامناً: التأخير أو التقصير</h3><div class="contract-terms"><article><b>التأخير أو التقصير</b><p>في حال تقصير أو تأخير الطرف الأول في تنفيذ أعمال الصيانة الدورية، يجب عليه إخطار الطرف الثاني بأسباب التأخير.</p></article><article><b>الإخلال بالالتزامات</b><p>في حال إخلال الطرف الأول بالتزاماته الجوهرية، يحق للطرف الثاني تعليق استحقاق الدفعات المستحقة للطرف الأول.</p></article><article><b>حدود المسؤولية</b><p>لا يتحمل الطرف الأول المسؤولية عن الأضرار غير المباشرة (سواء كانت مادية أو معنوية) مثل فقدان الأرباح أو توقف العمل أو غيرها، وتكون المسؤولية في جميع الأحوال محصورة بقيمة العقد المدفوعة من الطرف الثاني للطرف الأول.</p></article><article><b>إيقاف العقد</b><p>يحق للطرف الأول إيقاف العقد في حال عدم قيام الطرف الثاني بدفع الدفعات المستحقة في مواعيدها، على أن يكون الإيقاف بعد إنذار خطي لمدة لا تقل عن 7 أيام.</p></article></div></section><section class="contract-section"><h3>تاسعاً: فسخ العقد</h3><div class="contract-terms"><article><p>يحق لأي من الطرفين فسخ العقد في حال إخلال الطرف الآخر بالتزاماته الجوهرية مع إنذار خطي لمدة لا تقل عن 30 يوماً.</p></article><article><p>في حال فسخ العقد، يستحق الطرف الأول قيمة الأعمال التي تم تنفيذها فعلاً.</p></article><article><p>لا يحق للطرف الثاني فسخ العقد بسبب ظروفه المادية أو الإدارية أو تغير موقفه المالي، أو لأي سبب غير مبرر، وإلا أعتبر ذلك إخلالاً بالتزاماته.</p></article></div></section><section class="contract-section"><h3>عاشراً: المسؤولية عن الأعطال التي تتطلب قطع غيار</h3><div class="contract-terms"><article><b>الأعطال التي تتطلب قطع غيار</b><p>في حال وجود عطل بالمصعد يتطلب تغيير قطعة غيار، تتحمل الطرف الثاني قيمة القطعة وتكاليف الشحن والتركيب والنقل والخدمات اللوجستية، على أن تقوم الطرف الأول بتوفير القطعة وتنفيذ أعمال الاستبدال بأسرع وقت ممكن، ويتم وضع خطة لتفادي توقف المصعد لفترات طويلة.</p></article><article><b>الأعطال غير المشمولة</b><p>أما الأعطال الناتجة عن سوء الاستخدام أو التعديلات غير المصرح بها من قبل الطرف الثاني أو الغير، أو الأعطال الناتجة عن سوء التركيب أو التصنيع من قبل الغير والشركات المنفذة للتركيب أو التصنيع، أو ظروف قاهرة مثل كوارث طبيعية أو حرائق أو فيضانات أو سرقات وتخريب، أو انقطاع التيار الكهربائي أو عدم استقرار الجهد الكهربائي، أو عدم تنفيذ الصيانة الوقائية الدورية المتفق عليها في العقد، أو وجود أي تعديلات هيكلية في المبنى تؤثر على سلامة المصعد، فلا تكون الطرف الأول مسؤولة عنها وتتحمل الطرف الثاني أي تكاليف إضافية لإعادة التأهيل والصيانة.</p></article></div></section><section class="contract-section"><h3>نسخ العقد</h3><div class="contract-terms"><article><p>تم تحرير هذا العقد من نسختين (2) بيد كل طرف نسخة واحدة، وتعتبر جميعها نسخاً أصلية، وتسري أحكام هذا العقد اعتباراً من تاريخ توقيعه من الطرفين.</p></article></div></section>`}
function elevatorSection(i={}){const info=Object.assign({},specDefaults,i||{});return `<section class="contract-section"><h3>المواصفات الفنية للمصعد</h3>${specGroups.map(g=>`<div class="spec-doc-group"><h4>${g.tab}</h4><table class="contract-spec-table"><tbody>${g.fields.map(([k,l])=>`<tr><th>${l}</th><td>${esc(info[k]||"غير محدد")}</td></tr>`).join("")}</tbody></table></div>`).join("")}</section>`}
  function maintenanceElevatorSection(i={}){if(!Object.values(i||{}).some(Boolean))return "";return `<section class="contract-section"><h3>بيانات المصعد</h3><div class="contract-summary">${["count:عدد المصاعد","brand:الماركة","age:العمر","capacity:السعة","doorType:نوع الأبواب","usage:الاستخدام"].map(p=>{const [k,l]=p.split(":");return `<div><small>${l}</small><b>${i[k]||"غير محدد"}</b></div>`}).join("")}</div></section>`}
  function itemPicker(type){const items=defaultItems.filter(i=>i.type===type&&(sameCompany(i)));if(!items.length)return `<div class="form-note">لا توجد بنود افتراضية.</div>`;const secs=[...new Set(items.map(i=>i.section||"بنود عامة"))];return `<fieldset class="item-picker"><legend>البنود الافتراضية</legend>${secs.map(s=>`<div class="item-section"><strong>${s}</strong><label class="item-option select-all" style="font-size:12px;color:#60756f;border-bottom:1px solid #e0e8e4;padding:4px 0;margin-bottom:4px"><input type="checkbox" class="select-all-check" data-section="${esc(s)}"> <span>تحديد الكل</span></label>${items.filter(i=>(i.section||"بنود عامة")===s).map(i=>`<label class="item-option"><input type="checkbox" name="defaultItems" value="${i.id}"><span><b>${i.title}</b><small>${i.description||""} ${i.price?money(i.price):""}</small></span></label>`).join("")}</div>`).join("")}</fieldset>`}
  function customItems(){return `<fieldset class="item-picker"><legend>بنود إضافية</legend><div data-custom-items><div class="custom-item-row"><label>القسم<input name="customItemSection" placeholder="مثال: أعمال إضافية"></label><label>العنوان<input name="customItemTitle"></label><label>الوصف<textarea name="customItemDescription"></textarea></label><label>السعر<input name="customItemPrice" type="number"></label></div></div></fieldset>`}
  // Maintenance checklist items extracted from the approved maintenance reference images.
  const maintenanceSections=[
    {section:"غرفة المصعد",items:["فحص زيت المحرك والتأكد من سيره الطبيعي.","فحص قماش الفرامل.","فحص عمل الفرامل وتضبيطه وتشحيم المحاور.","فحص السيور والتأكد من سلامتها.","فحص سلكتور والطوابق.","فحص جهاز الهبوط الاضطراري.","فحص منظم السرعة وضبطه.","تنظيف أرضية الغرفة.","التأكد من سلامة التمديدات الكهربائية بالغرفة.","التأكد من عدم وجود تهريب مياه بالغرفة.","التأكد من عدم وجود أي تخزين بالغرفة.","التأكد من وجود التكييف بحالة سليمة."]},
    {section:"بئر المصعد",items:["فحص التوصيلات الكهربائية أعلى الصاعدة والتأكد من سلامتها.","فحص جهاز الريفيزيون في حالة الصعود والهبوط والتوقف.","فحص حبال الجر وشدادات الحبال.","فحص بكرات الحبال والتأكد من سلامتها.","تزييت وتشحيم أدلة سير الصاعدة والثقل.","فحص قواطع نهاية المشوار.","فحص مغناطيس الأدوار.","الكشف على مروحة الصاعدة."]},
    {section:"داخل المصعد",items:["الكشف على أزرار التحكم والتشغيل.","الكشف عن الإنارة والجرس والانتركوم.","تنظيف مجاري الأبواب."]},
    {section:"أبواب الطوابق",items:["فحص أبواب الأدوار وضبطها.","فحص محركات الأبواب.","فحص وتنظيف الشوك والكوالين.","فحص مفصلات الأبواب.","فحص الكابلات والمؤشرات والمبينات وضبط الإضاءة."]},
    {section:"حفرة البئر",items:["الكشف على بكرة منظم السرعة.","تنظيف وفحص قواطع نهاية المشوار.","فحص التوصيلات الكهربائية أسفل الصاعدة والتأكد من سلامتها.","تنظيف الحفرة."]}
  ];
  const defaultMaintenanceChecklist=()=>maintenanceSections.flatMap(sec=>sec.items.map((title,i)=>({id:`${sec.section}-${i}`,section:sec.section,title,status:"مطلوب",checked:false,note:""})));
  const checklistSource=x=>x?.maintenanceChecklist?.length?x.maintenanceChecklist:defaultMaintenanceChecklist();
  function maintenanceChecklistFields(x={},simple){const rows=checklistSource(x);if(simple)return `<div class="checklist-simple maint-simple">${maintenanceSections.map(sec=>`<div class="maint-block"><div class="maint-block-head"><h4>${esc(sec.section)}</h4><label class="maint-selall"><input type="checkbox" class="maint-selall-cb" data-section="${esc(sec.section)}"> الكل</label></div><div class="maint-grid">${sec.items.map((title,i)=>{const id=`${sec.section}-${i}`,old=rows.find(r=>r.id===id||r.title===title)||{};return `<label class="maint-check"><input type="checkbox" name="maintenanceChecklist" value="${esc(id)}" ${old.checked?"checked":""}><span>${esc(title)}</span></label>`}).join("")}</div></div>`).join("")}</div>`;return `<fieldset class="item-picker maintenance-checklist"><legend>بنود الصيانة الدورية</legend><div class="form-note">يمكن تعديل حالة كل بند، وسيتم حفظها ضمن بيانات العقد أو عرض السعر.</div><label class="maint-selall-top" style="margin-bottom:6px"><input type="checkbox" class="selectAllMaintenanceFull"> اختيار الكل</label>${maintenanceSections.map(sec=>`<div class="maintenance-section"><h4>${sec.section}</h4>${sec.items.map((title,i)=>{const id=`${sec.section}-${i}`,old=rows.find(r=>r.id===id||r.title===title)||{};return `<label class="maintenance-item"><input type="hidden" name="maintenanceSection" value="${esc(sec.section)}"><input type="hidden" name="maintenanceTitle" value="${esc(title)}"><input type="checkbox" name="maintenanceChecked" value="${esc(id)}" ${old.checked?"checked":""}><span>${esc(title)}</span><input name="maintenanceNote" value="${esc(old.note||"")}" placeholder="ملاحظة"></label>`}).join("")}</div>`).join("")}</fieldset>`}
  function collectMaintenanceChecklist(f){const simpleChecks=$$('[name="maintenanceChecklist"]:checked',f);if(simpleChecks.length){return simpleChecks.map(x=>{const parts=x.value.split('-'),section=parts.slice(0,-1).join('-'),idx=parseInt(parts[parts.length-1])||0;if(!isNaN(idx)){const found=maintenanceSections.find(s=>s.section===section);if(found&&found.items[idx])return {id:x.value,section,title:found.items[idx],status:"مطلوب",checked:true,note:""}}return {id:x.value,section:"بنود الصيانة",title:x.value,status:"مطلوب",checked:true,note:""}})}const sections=$$('[name="maintenanceSection"]',f),titles=$$('[name="maintenanceTitle"]',f),checks=new Set($$('[name="maintenanceChecked"]:checked',f).map(x=>x.value)),statuses=$$('[name="maintenanceStatus"]',f),notes=$$('[name="maintenanceNote"]',f),seen={};return titles.map((x,i)=>{const section=sections[i]?.value||"بنود الصيانة",idx=seen[section]||0,id=`${section}-${idx}`;seen[section]=idx+1;return {id,section,title:x.value,status:statuses[i]?.value||"مطلوب",checked:checks.has(id),note:notes[i]?.value||""}})}
  function renderMaintenanceChecklist(rows=[],emptyText="لا توجد بنود صيانة."){const list=rows.length?rows:defaultMaintenanceChecklist(),sections=[...new Set(list.map(x=>x.section||"بنود الصيانة"))];return list.length?`<div class="maintenance-doc-checklist">${sections.map(sec=>`<section><h4>${esc(sec)}</h4><table class="contract-spec-table maintenance-table"><thead><tr><th>الحالة</th><th>البند</th><th>النتيجة</th><th>ملاحظة</th></tr></thead><tbody>${list.filter(x=>(x.section||"بنود الصيانة")===sec).map(x=>`<tr><th>${x.checked?"✓":"□"}</th><td>${esc(x.title)}</td><td>${esc(x.status||"مطلوب")}</td><td>${esc(x.note||"")}</td></tr>`).join("")}</tbody></table></section>`).join("")}</div>`:`<p>${emptyText}</p>`}
  const collectCustom=f=>$$(".custom-item-row",f).map(r=>({section:$('[name="customItemSection"]',r)?.value.trim()||"بنود إضافية",title:$('[name="customItemTitle"]',r)?.value.trim()||"",description:$('[name="customItemDescription"]',r)?.value.trim()||"",price:Number($('[name="customItemPrice"]',r)?.value||0)})).filter(i=>i.title||i.description);
  const quoteTaxRate=0;
  function partOffers(part){const ownSuppliers=suppliers.filter(s=>sameCompany(s)),offers=(part.suppliers||[]).map(o=>({supplierId:o.supplierId||"",supplierName:o.supplierName||ownSuppliers.find(s=>s.id===o.supplierId)?.name||part.supplier||"مورد غير محدد",price:Number(o.price||0),leadTime:o.leadTime||"",warranty:o.warranty||""})).filter(o=>o.price>0);if(!offers.length&&Number(part.unitCost||0)>0)offers.push({supplierName:part.supplier||"سعر القطعة",price:Number(part.unitCost||0),leadTime:"",warranty:""});return offers.sort((a,b)=>a.price-b.price)}
  function bestPartOffer(part){return partOffers(part)[0]||null}
  function quotePartSelections(f){return $$('[data-quote-part]:checked',f).map(i=>{const part=parts.find(p=>p.id===i.value),offer=part&&bestPartOffer(part),qty=Number($$("[data-quote-part-qty]",f).find(q=>q.dataset.quotePartQty===i.value)?.value||1);return part&&offer?{part,offer,qty}:null}).filter(Boolean)}
  function quoteTotals(f){const base=Number(f.value?.value||0),picked=($$('[name="defaultItems"]:checked',f)||[]).reduce((s,i)=>s+Number(defaultItems.find(x=>String(x.id)===String(i.value))?.price||0),0),custom=($$('[name="customItemPrice"]',f)||[]).reduce((s,i)=>s+Number(i.value||0),0),quoteParts=quotePartSelections(f).reduce((s,x)=>s+(x.offer.price*x.qty),0),subtotal=base+picked+custom+quoteParts,tax=subtotal*quoteTaxRate,total=subtotal+tax;return {subtotal,tax,total,quoteParts}}
  function quoteTotalsBox(){return `<section class="panel quote-totals"><div class="contract-summary"><div><small>الإجمالي</small><b data-quote-total>${money(0)}</b></div></div><input type="hidden" name="subtotal"><input type="hidden" name="taxAmount"><input type="hidden" name="totalWithTax"></section>`}
