  function installationContractDetails(c){const company=c.company?.name||activeOwnerCompany()?.name||"شركة غير محددة",client=contractLabel(c),building=(c.buildings||[])[0]||{},install=c.installationInfo||{};return `<style>.installation-contract .contract-section{break-before:auto;page-break-before:auto}.installation-contract .contract-section:nth-of-type(1),.installation-contract .contract-section:nth-of-type(2),.installation-contract .contract-section:nth-of-type(3),.installation-contract .contract-spec-table,.installation-contract .signature-grid section{break-inside:avoid;page-break-inside:avoid}.installation-contract h3{break-after:avoid;page-break-after:avoid}.installation-contract p{orphans:3;widows:3}@media screen{.installation-contract .contract-section{break-before:auto;page-break-before:auto}}</style><div class="contract-document installation-contract"><div class="contract-topline"><span class="contract-type">عرض وعقد توريد وتركيب مصعد</span>${badge(c.status)}</div><div class="contract-number-strip"><span>&#x0631;&#x0642;&#x0645; &#x0627;&#x0644;&#x0639;&#x0642;&#x062f;</span><b>${c.id}</b></div><div class="installation-hero"><div><small>بسم الله الرحمن الرحيم</small><h3>عقد تركيب مصعد فل أوتوماتيك</h3><p>يسعدنا نحن ${company} أن نتقدم لسعادتكم بهذا العقد لتوريد وتركيب مصعد في موقعكم الموضح أدناه، وفق المواصفات الفنية والبنود العامة المعتمدة.</p></div><strong>${money(c.value)}</strong></div><div class="contract-summary"><div><small>السيد / الطرف الثاني</small><b>${client}</b></div><div><small>الموقع</small><b>${building.name||"غير محدد"} ${building.district||""}</b></div><div><small>تاريخ العقد</small><b>${c.startDate||"غير محدد"}</b></div><div><small>الإجمالي شامل الضريبة</small><b>${money(c.value)}</b></div><div><small>منشأة الإصدار</small><b>${company}</b></div><div><small>مدة التركيب</small><b>${install.installDuration||"45 يوماً"}</b></div>${c.deliveryDate?`<div><small>تاريخ التسليم</small><b>${c.deliveryDate}</b></div>`:""}</div><section class="contract-section"><h3>البند الأول: نطاق التوريد والتركيب</h3><p>${c.details||"يشمل العقد توريد وتركيب المصعد والسكة والأبواب والكابينة والمكينة ولوحة التحكم والتشغيل والاختبار وفق المواصفات الفنية المعتمدة، ويشمل العرض ضريبة القيمة المضافة ما لم يذكر خلاف ذلك."}${install.note?`<br>${esc(install.note)}`:""}</p></section><section class="contract-section"><h3>البند الثاني: الدفعات</h3><table class="contract-spec-table"><thead><tr><th>الدفعة</th><th>البيان</th><th>القيمة</th></tr></thead><tbody>${installationPayments(c.value)}</tbody></table></section><section class="contract-section"><h3>البند الثالث: المواصفات الفنية</h3><table class="contract-spec-table"><tbody>${installationSpecRows(c)}</tbody></table></section><section class="contract-section"><h3>البند الرابع: المباني والمواقع</h3>${renderTerms((c.buildings||[]).map(b=>({section:"مواقع العقد",title:b.name,description:`${b.district||""} ${b.mapUrl||""}`})),"لا توجد مواقع.")}</section><section class="contract-section"><h3>البند الخامس: الأحكام العامة</h3><div class="contract-terms"><article><b>المرفقات</b><p>تعتبر أي مرفقات أو مواصفات أو رسومات موقعة من الطرفين جزءا لا يتجزأ من هذا العقد.</p></article><article><b>التأخير والتعديلات</b><p>أي تأخير في الأعمال التحضيرية أو الدفعات أو تعديل المناسيب وفتحات الأبواب قد يترتب عليه تمديد مدة التسليم وتحميل الطرف الثاني أي تكاليف إضافية لازمة.</p></article><article><b>نقل الملكية</b><p>لا يحق للطرف الثاني بيع أو نقل أو التنازل عن المصعد قبل سداد قيمة العقد كاملة، وعند انتقال ملكية العقار يتم تزويد الطرف الأول ببيانات المالك الجديد.</p></article><article><b>الخلافات</b><p>تسوى الخلافات وديا، وفي حال تعذر ذلك يكون الاختصاص للجهة القضائية المختصة في موقع المشروع.</p></article></div></section><section class="contract-section"><h3>البند السادس: التوريد والتركيب والضمان</h3><div class="contract-terms"><article><b>التزام الطرف الأول</b><p>يلتزم الطرف الأول بتوريد وتركيب المصعد حسب أصول الصنعة ومتطلبات السلامة المعمول بها في المملكة العربية السعودية.</p></article><article><b>إيقاف الأعمال</b><p>يحق للطرف الأول إيقاف أعمال التوريد أو التركيب عند عدم سداد الدفعات المستحقة أو عدم جاهزية الأعمال التحضيرية.</p></article><article><b>الضمان والصيانة</b><p>يبدأ الضمان من تاريخ تشغيل المصعد ولمدة سنة، ولا يشمل سوء الاستخدام. تبدأ الصيانة بعد سداد قيمة العقد كاملة واستلام المصعد.</p></article></div></section><section class="contract-section"><h3>البند السابع: الأعمال التحضيرية على الطرف الثاني</h3><div class="contract-terms"><article><b>بيت المصعد وغرفة المحرك</b><p>تجهيز بيت المصعد وغرفة المحرك والعزل والإنارة والتهوية وفتحات الأبواب حسب الأبعاد المعتمدة قبل بدء الأعمال.</p></article><article><b>التيار الكهربائي والمستودع</b><p>تأمين التيار الكهربائي المناسب ومكان آمن لحفظ أجزاء المصعد طوال فترة التركيب.</p></article><article><b>السقالة والتدريب</b><p>تأمين السقالة عند الحاجة، وتعيين من يراه الطرف الثاني مناسبا لتدريبه على إنزال الكابينة يدويا في حالات الطوارئ.</p></article></div></section><section class="contract-section"><h3>البنود الإضافية</h3>${renderTerms([...(c.items||[]),...(c.customItems||[])],"لا توجد بنود إضافية.")}</section><section class="contract-section"><h3>بنود الصيانة المتفق عليها</h3><div class="maintenance-doc-checklist">${c.maintenanceChecklist?.length?c.maintenanceChecklist.map(x=>'<label>✓ '+esc(x.title||x)+'</label>').join(''):"لم يتم تحديد بنود صيانة."}</div></section>${c.deliveryDate&&c.maintenanceEndDate?`<section class="contract-section"><h3>فترة الصيانة</h3><p>تبدأ فترة الصيانة من تاريخ تسليم المصعد <b>(${c.deliveryDate})</b> إلى تاريخ <b>(${c.maintenanceEndDate})</b>، على أن تشمل أعمال الصيانة الدورية والطارئة وفق بنود الصيانة المتفق عليها أعلاه.</p></section>`:""}<section class="contract-section"><h3>خامساً: الضمان على أعمال الصيانة</h3><div class="contract-terms"><article><b>الضمان</b><p>تضمن الشركة جودة أعمال الصيانة لمدة <b>30 يوماً</b> من تاريخ تنفيذها.</p></article><article><b>تكرار العطل</b><p>في حال تكرار نفس العطل خلال فترة الضمان يتم إصلاحه بدون أي رسوم إضافية.</p></article></div></section><section class="contract-section"><h3>سادساً: التزامات الطرف الثاني</h3><div class="contract-terms"><article><b>القواعد الأساسية</b><ol style="margin:0;padding-right:20px"><li>توفير مصدر كهرباء مستقر للمصعد.</li><li>إبلاغ الشركة فور حدوث أي عطل.</li><li>عدم السماح لأي جهة غير معتمدة بالتدخل في أعمال الصيانة.</li></ol></article></div></section><section class="contract-section"><h3>سابعاً: المسؤولية والسلامة</h3><div class="contract-terms"><article><b>مسؤولية الصيانة</b><p>يلتزم الطرف الأول بالمحافظة على سلامة المصعد أثناء فترة العقد.</p></article><article><b>المسؤولية عن الأعطال</b><p>في حال حدوث عطل نتيجة إهمال في الصيانة تتحمل الشركة المسؤولية الفنية.</p></article></div></section><section class="contract-section"><h3>ثامناً: التأخير أو التقصير</h3><div class="contract-terms"><article><b>حق الطرف الثاني</b><p>في حال عدم التزام الطرف الأول بأعمال الصيانة أو التأخر في إصلاح الأعطال:</p><ol style="margin:0;padding-right:20px"><li>يحق للطرف الثاني خصم جزء من قيمة العقد.</li><li>أو فسخ العقد دون أي غرامة.</li></ol></article></div><div class="contract-terms"><article><b>حدود المسؤولية</b><p>الشركة غير مسؤولة عن الأعطال الناتجة عن انقطاع الكهرباء أو سوء الاستخدام أو الكوارث الطبيعية.</p></article><article><b>إيقاف العقد لعدم السداد</b><p>يحق للطرف الأول تعليق خدمات الصيانة عند تأخر السداد أكثر من <b>30 يوماً</b>.</p></article></div></section><section class="contract-section"><h3>تاسعاً: فسخ العقد</h3><div class="contract-terms"><article><b>حق الفسخ</b><p>يحق للطرف الثاني فسخ العقد فوراً في الحالات التالية:</p><ol style="margin:0;padding-right:20px"><li>عدم تنفيذ الصيانة الدورية.</li><li>تكرار الأعطال بسبب الإهمال.</li><li>تأخر الشركة عن إصلاح الأعطال لفترة طويلة.</li></ol></article></div></section><section class="contract-section"><h3>عاشراً: المسؤولية عن الأعطال التي تتطلب قطع غيار</h3><div class="contract-terms"><article><b>الإبلاغ بالأعطال</b><p>يلتزم الطرف الأول بإبلاغ الطرف الثاني كتابياً أو عبر وسائل التواصل المعتمدة عن أي عطل أو خلل في المصعد يتطلب استبدال قطع غيار أو إجراء إصلاحات ضرورية لضمان التشغيل الآمن.</p></article><article><b>حق الإيقاف عن عدم الموافقة</b><p>في حال تم إشعار الطرف الثاني بالحاجة إلى هذه الإصلاحات أو قطع الغيار، ولم يقم بالموافقة على تنفيذها أو تأخر في توفيرها خلال مدة معقولة،</p><p>يحق للطرف الأول إيقاف تشغيل المصعد مؤقتاً إذا رأى أن استمرار تشغيله يشكل خطراً على سلامة المستخدمين، وذلك حتى يتم تنفيذ الإصلاحات أو استبدال قطع الغيار المطلوبة.</p></article><article><b>مسؤولية العمليات بدون علم الشركة</b><p>يقر الطرف الثاني بأن تشغيل المصعد بدون علم الطرف الأول في هذه الحالة يكون على مسؤوليته الكاملة، ولا تتحمل شركة الصيانة (الطرف الأول) أي مسؤولية قانونية أو مالية عن أي أضرار قد تحدث للأشخاص أو الممتلكات نتيجة لذلك.</p></article></div></section><section class="contract-section"><h3>نسخ العقد</h3><p>حرر هذا العقد من نسختين أصليتين بيد كل طرف نسخة للعمل بموجبها.</p></section>${signatureArea(c,c.companyOwnerId)}</div>`}
  function contractDetails(c){if(c.type==="\u062a\u0631\u0643\u064a\u0628")return installationContractDetails(c);return `<div class="contract-document"><div class="contract-topline"><span class="contract-type">&#x0639;&#x0642;&#x062f; ${c.type}</span>${badge(c.status)}</div><div class="contract-number-strip"><span>&#x0631;&#x0642;&#x0645; &#x0627;&#x0644;&#x0639;&#x0642;&#x062f;</span><b>${c.id}</b></div><section class="contract-section party-section"><h3>&#x0627;&#x0644;&#x0637;&#x0631;&#x0641; &#x0627;&#x0644;&#x062b;&#x0627;&#x0646;&#x064a;</h3><p class="pdf-party-name">${contractLabel(c)}</p></section><div class="contract-title"><div><span>&#x0642;&#x064a;&#x0645;&#x0629; &#x0627;&#x0644;&#x0639;&#x0642;&#x062f;</span><b>${money(c.value)}</b></div></div><div class="contract-summary"><div><small>&#x0628;&#x062f;&#x0627;&#x064a;&#x0629; &#x0627;&#x0644;&#x0639;&#x0642;&#x062f;</small><b>${c.startDate||"&#x063a;&#x064a;&#x0631; &#x0645;&#x062d;&#x062f;&#x062f;"}</b></div><div><small>&#x0646;&#x0647;&#x0627;&#x064a;&#x0629; &#x0627;&#x0644;&#x0639;&#x0642;&#x062f;</small><b>${c.endDate||"&#x063a;&#x064a;&#x0631; &#x0645;&#x062d;&#x062f;&#x062f;"}</b></div><div><small>&#x0645;&#x0646;&#x0634;&#x0623;&#x0629; &#x0627;&#x0644;&#x0625;&#x0635;&#x062f;&#x0627;&#x0631;</small><b>${c.company?.name||activeOwnerCompany()?.name||"&#x063a;&#x064a;&#x0631; &#x0645;&#x062d;&#x062f;&#x062f;"}</b></div></div>${maintenanceElevatorSection(c.elevatorInfo)}<section class="contract-section"><h3>&#x0628;&#x0646;&#x0648;&#x062f; &#x0627;&#x0644;&#x0635;&#x064a;&#x0627;&#x0646;&#x0629; &#x0627;&#x0644;&#x062f;&#x0648;&#x0631;&#x064a;&#x0629;</h3>${renderMaintenanceChecklist(c.maintenanceChecklist)}</section><section class="contract-section"><h3>&#x0627;&#x0644;&#x0645;&#x0628;&#x0627;&#x0646;&#x064a; &#x0648;&#x0627;&#x0644;&#x0645;&#x0648;&#x0627;&#x0642;&#x0639;</h3>${renderTerms((c.buildings||[]).map(b=>({section:"&#x0645;&#x0648;&#x0627;&#x0642;&#x0639; &#x0627;&#x0644;&#x0639;&#x0642;&#x062f;",title:b.name,description:`${b.district||""} ${b.mapUrl||""}`})) ,"&#x0644;&#x0627; &#x062a;&#x0648;&#x062c;&#x062f; &#x0645;&#x0648;&#x0627;&#x0642;&#x0639;.")}</section><section class="contract-section"><h3>&#x0627;&#x0644;&#x0628;&#x0646;&#x0648;&#x062f; &#x0627;&#x0644;&#x0627;&#x0641;&#x062a;&#x0631;&#x0627;&#x0636;&#x064a;&#x0629;</h3>${renderTerms(c.items,"&#x0644;&#x0627; &#x062a;&#x0648;&#x062c;&#x062f; &#x0628;&#x0646;&#x0648;&#x062f; &#x0627;&#x0641;&#x062a;&#x0631;&#x0627;&#x0636;&#x064a;&#x0629;.")}</section><section class="contract-section"><h3>&#x0627;&#x0644;&#x0628;&#x0646;&#x0648;&#x062f; &#x0627;&#x0644;&#x0625;&#x0636;&#x0627;&#x0641;&#x064a;&#x0629;</h3>${renderTerms(c.customItems,"&#x0644;&#x0627; &#x062a;&#x0648;&#x062c;&#x062f; &#x0628;&#x0646;&#x0648;&#x062f; &#x0625;&#x0636;&#x0627;&#x0641;&#x064a;&#x0629;.")}</section><section class="contract-section"><h3>&#x0646;&#x0637;&#x0627;&#x0642; &#x0627;&#x0644;&#x0639;&#x0645;&#x0644;</h3><p>${c.details||"&#x0644;&#x0627; &#x062a;&#x0648;&#x062c;&#x062f; &#x062a;&#x0641;&#x0627;&#x0635;&#x064a;&#x0644; &#x0625;&#x0636;&#x0627;&#x0641;&#x064a;&#x0629;."}</p></section>${maintenanceClauses()}${signatureArea(c,c.companyOwnerId)}</div>`}

  function ticketDetails(t){const loc=t.assignedTo?locations.find(l=>cleanId(l.identity)===cleanId(t.assignedTo)&&l.live):null;return `<div class="report-details"><dl><dt>العميل / المنشأة</dt><dd>${t.clientCompanyName||t.clientName||"غير محدد"}</dd><dt>رقم البلاغ</dt><dd>${t.id}</dd><dt>العنوان</dt><dd>${t.title}</dd><dt>الوصف</dt><dd>${t.description}</dd><dt>العقد</dt><dd>${t.contractId||"غير مرتبط"}</dd><dt>الموقع</dt><dd>${t.building?.name||"غير محدد"} ${t.building?.district||""}</dd><dt>الحالة</dt><dd>${t.status}</dd><dt>المسند إليه</dt><dd>${staff.find(s=>s.identity===t.assignedTo)?.name||t.assignedTo||"غير مسند"}</dd><dt>موقع الفني القادم</dt><dd>${loc?mapLink(loc.mapUrl,"عرض الموقع المباشر"):"غير متاح حاليًا"}</dd></dl></div>${elevatorSection(t.elevatorInfo)}${signatureArea(t)}`}
  function visitReport(v){return reports.find(r=>r.visitId===v.id)}
  function canWriteReport(v){return ["technician","engineer"].includes(session.role)&&cleanId(v.assignedTo)===cleanId(session.id)&&!visitReport(v)}
  function visitRoom(v){return `shumoos-${String(v.id||"visit").replace(/[^a-zA-Z0-9-]/g,"")}`}
  function visitCommunication(v){const c=contracts.find(x=>x.id===v.contractId)||{},tech=staff.find(s=>cleanId(s.identity)===cleanId(v.assignedTo))||{},msgs=visitMessages.filter(m=>m.visitId===v.id).slice(-50),room=visitRoom(v),meet=`https://meet.jit.si/${room}`,phone=tech.phone||tech.mobile||v.building?.guardMobile||c.buildings?.[0]?.guardMobile||"";return `<div class="visit-comms"><div class="quick-grid"><a class="quick-card" target="_blank" rel="noopener" href="${meet}"><b>مكالمة فيديو</b><small>غرفة الزيارة ${v.id}</small></a><a class="quick-card" target="_blank" rel="noopener" href="${phone?`tel:${phone}`:meet}"><b>مكالمة صوتية</b><small>${phone||"عبر غرفة الاجتماع"}</small></a><button class="quick-card" type="button" data-copy-invite="${meet}"><b>نسخ رابط الاجتماع</b><small>للمشاركة مع الطرف الآخر</small></button></div><section class="panel"><h3>رسائل الزيارة</h3><div class="visit-chat">${msgs.length?msgs.map(m=>`<article><b>${esc(m.senderName)}</b><small>${esc(m.createdAt)}</small><p>${esc(m.text)}</p></article>`).join(""):"لا توجد رسائل بعد."}</div><form class="modal-form" data-form="visit-message"><input type="hidden" name="visitId" value="${esc(v.id)}"><label>رسالة جديدة<textarea name="message" required placeholder="اكتب رسالة مرتبطة بهذه الزيارة"></textarea></label><button class="btn-primary">إرسال الرسالة</button></form></section></div>`}
  function visitActions(v){const r=visitReport(v);let b=`<button class="action-btn primary" data-visit-comms="${v.id}">تواصل</button>`;if(r)b+=` <button class="action-btn primary" data-view-report="${r.id}">عرض التقرير</button>`;if(canWriteReport(v))b+=` <button class="action-btn primary" data-action="visit-report:${v.id}">تعبئة التقرير</button>`;if(v.status==="بانتظار الاعتماد"&&session.role==="client"&&matchClient(v))b+=` <button class="action-btn success" data-approve-visit="${v.id}">اعتماد الزيارة</button>`;if(v.status==="بانتظار الاعتماد"&&["technician","engineer"].includes(session.role)&&cleanId(v.assignedTo)===cleanId(session.id))b+=` <button class="action-btn" data-enter-code="${v.id}">إدخال رمز العميل</button>`;if(v.status==="بانتظار التقييم"&&session.role==="client"&&matchClient(v))b+=` <button class="action-btn primary" data-rate-visit="${v.id}">تقييم الفني</button>`;if(v.rating)b+=` <span class="badge success">${"★".repeat(v.rating.stars)}${"☆".repeat(5-v.rating.stars)}</span>`;return b}
  function meetingUrl(m){return m.url||`https://meet.jit.si/${m.room}`}
  function meetingInvitees(m){return (m.invitees||[]).map(id=>staff.find(s=>cleanId(s.identity)===cleanId(id))?.name||users.find(u=>cleanId(u.id)===cleanId(id))?.name||id).join("، ")||"كل الفريق"}
  function meetingsPage(){const rows=meetings.filter(m=>sameCompany(m)||m.createdBy===session.id).map(m=>[m.title,fmtDate(m.scheduledAt),meetingInvitees(m),m.createdByName||"—",`<a class="action-btn primary" target="_blank" rel="noopener" href="${meetingUrl(m)}">دخول</a> <button class="action-btn" data-copy-invite="${meetingUrl(m)}">نسخ</button> <button class="action-btn" data-share-invite="${meetingUrl(m)}" data-share-label="${esc(m.title)}">مشاركة</button>`]);return head("الاجتماعات","إنشاء اجتماعات ودعوة أعضاء الفريق",["owner","company_admin","admin"].includes(session.role)?'<button class="btn-primary" data-action="meeting">اجتماع جديد</button>':"")+(rows.length?table(["العنوان","الموعد","المدعوون","المنشئ","الإجراء"],rows):empty("لا توجد اجتماعات","أنشئ اجتماعًا جديدًا وشارك رابطه مع الأعضاء."))}
  function meetingForm(){const members=[...staff.filter(s=>sameCompany(s)),...users.filter(u=>["owner","company_admin","technician"].includes(u.role))],opts=members.map(m=>`<label class="check"><input type="checkbox" name="invitees" value="${esc(m.identity||m.id)}"> ${esc(m.name)} - ${roles[m.role]||m.role}</label>`).join("")||"<p>لا يوجد أعضاء متاحون.</p>";return `<form class="modal-form" data-form="meeting"><label>عنوان الاجتماع<input name="title" required placeholder="مثال: تنسيق زيارة عاجلة"></label><label>الموعد<input name="scheduledAt" type="datetime-local" required></label><label>ملاحظات<textarea name="notes" placeholder="موضوع الاجتماع أو تعليمات مختصرة"></textarea></label><fieldset class="item-picker"><legend>دعوة الأعضاء</legend>${opts}</fieldset><button class="btn-primary">إنشاء الاجتماع</button>${aiDraftBtn("meeting")}</form>`}
  function reportDetails(r){const v=visits.find(x=>x.id===r.visitId)||{},c=contracts.find(x=>x.id===r.contractId)||{};const quoteBtn=["owner","company_admin","admin"].includes(session.role)?`<div class="contract-actions"><button class="btn-primary" data-action="quote-from-report:${r.id}">إنشاء عرض سعر من التقرير</button></div>`:"";return `<div class="contract-document visit-report-doc"><div class="contract-topline"><span class="contract-type">تقرير زيارة فنية</span>${badge(r.status||"بانتظار اعتماد العميل")}</div><div class="contract-title"><div><span>رقم التقرير</span><b>${r.id}</b></div><strong>${r.technician||r.technicianId||"الفني"}</strong></div><div class="contract-summary"><div><small>العقد</small><b>${r.contractId||"زيارة كشفية"}</b></div><div><small>الطرف الثاني</small><b>${partyLabel(r)}</b></div><div><small>الموقع</small><b>${v.building?.name||r.buildingName||"غير محدد"}</b></div><div><small>موعد الزيارة</small><b>${fmtDate(v.scheduledAt)}</b></div><div><small>تاريخ التقرير</small><b>${r.createdAt||"غير محدد"}</b></div><div><small>حالة المصعد</small><b>${r.elevatorStatus||"غير محدد"}</b></div></div><section class="contract-section"><h3>الأعمال المنفذة</h3><p>${r.workDone||"لا توجد تفاصيل."}</p></section><section class="contract-section"><h3>الأعطال والملاحظات الفنية</h3><p>${r.issues||"لا توجد ملاحظات."}</p></section><section class="contract-section"><h3>قطع الغيار المطلوبة / المستخدمة والتوصيات</h3><p>${r.parts||"لا توجد قطع مسجلة."}</p><p>${r.recommendations||"لا توجد توصيات."}</p></section><section class="contract-section"><h3>صور أو روابط مرفقة</h3><p>${r.attachments||"لا توجد مرفقات."}</p></section>${signatureArea(r)}<div class="form-note decision-note">هذا التقرير محفوظ للعرض فقط ولا يمكن تعديله بعد إرساله.</div>${quoteBtn}</div>`}
  function reportForm(v){const c=contracts.find(x=>x.id===v.contractId)||{};return `<form class="modal-form visit-report-form" data-form="visit-report"><input type="hidden" name="visitId" value="${esc(v.id)}"><div class="form-note">سيتم حفظ التقرير نهائيًا بعد الإرسال، ولن يمكن تعديله لاحقًا.</div><fieldset class="item-picker"><legend>بيانات الزيارة</legend><div class="report-details"><dl><dt>الزيارة</dt><dd>${v.id}</dd><dt>العقد</dt><dd>${v.contractId||"زيارة كشفية قبل العقد"}</dd><dt>الطرف الثاني</dt><dd>${partyLabel(v)}</dd><dt>الموقع</dt><dd>${v.building?.name||"غير محدد"} ${v.building?.district||""}</dd><dt>الموعد</dt><dd>${fmtDate(v.scheduledAt)}</dd></dl></div></fieldset><label>حالة المصعد بعد الزيارة<select name="elevatorStatus" required><option>يعمل بشكل طبيعي</option><option>يعمل مع ملاحظات</option><option>متوقف عن العمل</option><option>يحتاج زيارة إضافية</option></select></label><label>الأعمال المنفذة<textarea name="workDone" required placeholder="اكتب ما تم تنفيذه أثناء الزيارة"></textarea></label><label>الأعطال أو الملاحظات الفنية<textarea name="issues" placeholder="اكتب الأعطال أو الملاحظات إن وجدت"></textarea></label><label>القطع المستخدمة أو المطلوبة<textarea name="parts" placeholder="مثال: حساس باب، زيت، لوحة تحكم..."></textarea></label><label>التوصيات<textarea name="recommendations" placeholder="توصيات الصيانة أو السلامة"></textarea></label><label>روابط صور أو مرفقات<textarea name="attachments" placeholder="يمكن لصق روابط صور أو ملفات هنا"></textarea></label><button class="btn-primary">إرسال التقرير النهائي</button></form>`}
  function scoutingVisitForm(){return `<form class="modal-form" data-form="scouting-visit">${aiAssistantHTML("visit")}<fieldset class="item-picker"><legend>بيانات العميل والمنشأة</legend><label>هوية العميل<input name="clientId" data-client-id></label><label>اسم العميل<input name="clientName"></label><label>الرقم الموحد للمنشأة<input name="clientCompanyUnifiedNumber" data-company-number></label><label>اسم المنشأة<input name="clientCompanyName"></label><div data-client-preview class="client-preview">أدخل الهوية أو الرقم الموحد لجلب البيانات المسجلة.</div></fieldset><fieldset class="item-picker"><legend>موقع الكشف</legend><label>اسم المبنى<input name="buildingName" required></label><label>الحي<input name="buildingDistrict" required></label><label>رابط الخريطة<input name="buildingMapUrl" type="url"></label><label>جوال المسؤول<input name="buildingGuardMobile"></label></fieldset>${elevatorFields()}<label>موعد الزيارة الكشفية<input name="scheduledAt" type="datetime-local" required></label><label>ملاحظات أولية<textarea name="notes"></textarea></label><button class="btn-primary">إنشاء وإسناد تلقائي</button>${aiDraftBtn("visit")}</form>`}
  function updateQuoteTypeFields(f){if(!f?.matches?.('[data-form="quote"]'))return;const isInstall=f.type?.value==="تركيب";const installFields=f.querySelector(".quote-install-fields");if(installFields)installFields.style.display=isInstall?"":"none";const maintenanceSection=f.querySelector(".quote-maintenance-fields");if(maintenanceSection)maintenanceSection.style.display=isInstall?"none":""}
  function quotePaymentPlanFields(plan){const parts=(plan&&plan.length)?plan:defaultPaymentPlan();return `<fieldset class="item-picker"><legend>جدول الدفعات</legend><div class="form-note">حدد نسب الدفعات بناءً على المبلغ الإجمالي أعلاه. سيتم تحديث القيم تلقائياً عند تغيير المبلغ.</div><table class="payment-plan-table" style="width:100%;border-collapse:collapse;margin-top:8px"><thead><tr style="background:#0d312f;color:#fff;font-size:13px"><th style="padding:8px 10px;text-align:right">الدفعة</th><th style="padding:8px 10px;text-align:right">البيان</th><th style="padding:8px 10px;text-align:center;width:80px">النسبة %</th><th style="padding:8px 10px;text-align:center;width:100px">القيمة</th></tr></thead><tbody>${parts.map((p,i)=>{const pct=p.percent||(Array.isArray(p)?p[2]*100:50);const label=p.label||(Array.isArray(p)?p[0]:`الدفعة ${i+1}`);const desc=p.description||(Array.isArray(p)?p[1]:"");return `<tr style="border-bottom:1px solid #dfe8e4"><td><input type="hidden" name="paymentLabel" value="${esc(label)}">${esc(label)}</td><td><input type="hidden" name="paymentDesc" value="${esc(desc)}">${esc(desc)}</td><td style="text-align:center"><input name="paymentPct" type="number" min="0" max="100" step="0.5" value="${pct}" style="width:70px;text-align:center;padding:6px;border:1px solid #dfe8e4;border-radius:8px;font-family:Cairo,sans-serif;font-weight:700"></td><td style="text-align:center;font-weight:800;color:#17413e" data-payment-amount>${money(0)}</td></tr>`}).join("")}</tbody></table></fieldset>`}
  function updateQuotePaymentPlan(f){if(!f?.matches?.('[data-form="quote"]'))return;const value=Number(f.value?.value||0);const pcts=$$('[name="paymentPct"]',f);const amounts=$$('[data-payment-amount]',f);pcts.forEach((input,i)=>{if(amounts[i])amounts[i].textContent=money(value*Number(input.value||0)/100)})}
  function quoteForm(r=null){const detail=r?`قطع الغيار المطلوبة: ${r.parts||"غير محدد"}\nالتوصيات: ${r.recommendations||"غير محدد"}\nمرجع التقرير: ${r.id}`:"";return `<form class="modal-form" data-form="quote">${r?`<input type="hidden" name="reportId" value="${esc(r.id)}">`:""}${aiAssistantHTML("quote")}<fieldset class="item-picker"><legend>بيانات العميل والمنشأة</legend><label>هوية العميل<input name="clientId" data-client-id value="${esc(r?.clientId)}"></label><label>اسم العميل<input name="clientName" value="${esc(r?.clientName)}"></label><label>الرقم الموحد للمنشأة<input name="clientCompanyUnifiedNumber" data-company-number value="${esc(r?.clientCompanyUnifiedNumber)}"></label><label>اسم المنشأة<input name="clientCompanyName" value="${esc(r?.clientCompanyName)}"></label><label>العميل الظاهر في العرض<input name="client" value="${esc(r?.clientCompanyName||r?.clientName)}" required></label><div data-client-preview class="client-preview">أدخل الهوية أو الرقم الموحد لجلب البيانات المسجلة.</div></fieldset><label>العنوان<input name="title" required value="${r?"عرض سعر بناء على تقرير كشف":""}"></label><label>نوع عرض السعر<select name="type"><option>تركيب</option><option>صيانة</option></select></label><div class="quote-install-fields">${elevatorFields()}${quotePaymentPlanFields(r?.paymentPlan)}</div><div class="quote-maintenance-fields">${maintenanceChecklistFields()}</div>${itemPicker("quote")}${quotePartsPicker()}${customItems()}<label>قيمة أساسية قبل الضريبة<input name="value" type="number" min="0" step="0.01" value="0" required></label>${quoteTotalsBox()}<label>التفاصيل<textarea name="details">${esc(detail)}</textarea></label><button class="btn-primary">حفظ وتوجيه العرض للعميل</button>${aiDraftBtn("quote")}</form>`}
  function fixedPdfFooter(){const footer=(activeOwnerCompany()?.pdfFooter||"").trim();return footer?`<div class="fixed-pdf-footer">${esc(footer).replace(/\n/g,"<br>")}</div>`:""}
  const pdfAction=(type,id)=>`<div class="contract-actions pdf-actions"><button class="btn-primary" data-pdf-doc="${type}" data-pdf-id="${id}">⬇ تحميل PDF</button> <button class="btn-secondary" data-pdf-doc="${type}" data-pdf-id="${id}" data-pdf-clean="true">بدون ترويسة</button> <button class="btn-secondary" data-pdf-doc="${type}" data-pdf-id="${id}" data-pdf-letterhead="true">على مطبوعات الشركة</button> <button class="btn-secondary" data-pdf-preview="${type}" data-pdf-id="${id}">👁 عرض</button></div>`;
  function quoteDetails(q){const total=Number(q.totalWithTax??q.subtotal??q.value??0),party=q.client||q.clientCompanyName||q.clientName||"غير محدد",isInstall=q.type==="تركيب";return `<div class="contract-document"><div class="contract-topline"><span class="contract-type">عرض سعر ${q.type?"- "+q.type:""}</span>${badge(q.status||"بانتظار الرد")}</div><div class="contract-number-strip"><span>رقم عرض السعر</span><b>${q.id}</b></div><section class="contract-section party-section"><h3>الطرف الموجه إليه عرض السعر</h3><p class="pdf-party-name">${party}</p></section><div class="contract-title"><div><span>الإجمالي</span><b>${money(total)}</b></div></div><div class="contract-summary"><div><small>العنوان</small><b>${q.title||"عرض سعر"}</b></div><div><small>تاريخ الإصدار</small><b>${q.createdAt||"غير محدد"}</b></div><div><small>مرجع الكشف</small><b>${q.reportId||"?"}</b></div></div>${isInstall?elevatorSection(q.elevatorInfo):""}${isInstall?`<section class="contract-section"><h3>جدول الدفعات</h3><table class="contract-spec-table"><thead><tr><th>الدفعة</th><th>البيان</th><th>القيمة</th></tr></thead><tbody>${installationPayments(total,q.paymentPlan)}<tr class="total-row"><td colspan="2" style="text-align:left;font-weight:900">الإجمالي</td><td style="text-align:center;font-weight:900">${money(total)}</td></tr></tbody></table></section>`:""}${!isInstall?`<section class="contract-section"><h3>بنود الصيانة الدورية</h3>${renderMaintenanceChecklist(q.maintenanceChecklist)}</section>`:""}<section class="contract-section"><h3>قطع الغيار بأقل أسعار الموردين</h3>${renderTerms(q.partsItems,"لا توجد قطع غيار في العرض.")}</section><section class="contract-section"><h3>البنود الافتراضية</h3>${renderTerms(q.items,"لا توجد بنود.")}</section><section class="contract-section"><h3>البنود الإضافية</h3>${renderTerms(q.customItems,"لا توجد بنود إضافية.")}</section><section class="contract-section"><h3>التفاصيل</h3><p>${q.details||"لا توجد تفاصيل."}</p></section>${signatureArea(q)}</div>`}

  function claimDetails(cl){const c=contracts.find(x=>x.id===cl.contractId)||{};return `<div class="contract-document"><div class="contract-topline"><span class="contract-type">مستخلص مالي</span>${badge(cl.status||"قيد المراجعة")}</div><div class="contract-title"><div><span>رقم المستخلص</span><b>${cl.id}</b></div><strong>${money(cl.value)}</strong></div><div class="contract-summary"><div><small>العقد</small><b>${cl.contractId||"غير محدد"}</b></div><div><small>الطرف الثاني</small><b>${contractLabel(c)}</b></div><div><small>الفترة</small><b>${cl.period||"غير محددة"}</b></div><div><small>تاريخ الإنشاء</small><b>${cl.createdAt||"غير محدد"}</b></div></div><section class="contract-section"><h3>بيان المستخلص</h3><p>مستخلص عن الفترة الموضحة أعلاه بمبلغ إجمالي ${money(cl.value)} وفق بيانات العقد والخدمات المسجلة في النظام.</p></section>${signatureArea(cl)}</div>`}
  function docPayload(type,id){let title="مستند",body="",shareText="";if(type==="contract"){const c=visibleContracts().find(x=>x.id===id);if(c){title=`عقد ${c.id} - ${contractLabel(c)}`;body=contractDetails(c);shareText=`${title} بصيغة PDF`}}if(type==="ticket"){const t=visibleTickets().find(x=>x.id===id);if(t){title=`بلاغ ${t.id} - ${t.clientCompanyName||t.clientName||"عميل"}`;body=ticketDetails(t);shareText=`${title} بصيغة PDF`}}if(type==="report"){const r=reports.filter(x=>session.role==="client"?matchClient(x):sameCompany(x)).find(x=>x.id===id);if(r){title=`تقرير زيارة ${r.id}`;body=reportDetails(r);shareText=`${title} بصيغة PDF`}}if(type==="quote"){const q=quotes.filter(x=>session.role==="client"?matchClient(x):sameCompany(x)).find(x=>x.id===id);if(q){title=`عرض سعر ${q.id} - ${q.client||"عميل"}`;body=quoteDetails(q);shareText=`${title} بصيغة PDF`}}if(type==="claim"){const cl=read("misadClaims").filter(sameCompany).find(x=>x.id===id);if(cl){title=`مستخلص ${cl.id}`;body=claimDetails(cl);shareText=`${title} بصيغة PDF`}}return {title,body,shareText:shareText||title}}
  
var pdfCss;function splitLongTables(h){var regex=/<table[^>]*class="[^"]*(?:contract-spec-table|maintenance-table)[^"]*"[^>]*>([\s\S]*?)<\/table>/gi;return h.replace(regex,function(tbl){var theadMatch=tbl.match(/<thead[^>]*>([\s\S]*?)<\/thead>/i);var theadHtml=theadMatch?theadMatch[0]:'';var tbodyMatch=tbl.match(/<tbody[^>]*>([\s\S]*?)<\/tbody>/i);if(!tbodyMatch)return tbl;var rows=tbodyMatch[1].match(/<tr[^>]*>([\s\S]*?)<\/tr>/gi);if(!rows||rows.length<=15)return tbl;var tableOpen=tbl.match(/<table[^>]*>/i)[0];var chunks=[];for(var i=0;i<rows.length;i+=15){chunks.push(rows.slice(i,i+15).join(''))}var result='';for(var c=0;c<chunks.length;c++){result+=tableOpen+theadHtml+'<tbody>'+chunks[c]+'</tbody></table>';if(c<chunks.length-1)result+='<div style="page-break-before:always;break-before:page;height:0;margin:0;padding:0"></div>'}return result})}

