  // ===== Visit Approval & Rating System =====
  async function approveVisitAsClient(visitId) {
    try {
      const r = await fetch("/api/visits/approve-by-client", {method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({visitId, userId:session.id})});
      const d = await r.json();
      if (r.ok && d.ok) { toast("تم اعتماد الزيارة بنجاح"); refresh(); render("visits"); }
      else toast(d.error || "فشل الاعتماد");
    } catch { toast("تعذر الاتصال بالخادم"); }
  }
  function approveVisitUI(v) {
    return `<div style="padding:12px"><h3 style="color:#0d312f;margin:0 0 8px">اعتماد الزيارة</h3><p style="color:#60756f;margin:0 0 16px">الزيارة ${v.id} بانتظار اعتمادك.</p><div style="display:flex;gap:12px;flex-wrap:wrap"><button class="btn-primary" onclick="(async()=>{const r=await fetch('/api/visits/approve-by-client',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({visitId:'${v.id}',userId:'${session.id}'})});const d=await r.json();if(r.ok&&d.ok){toast('تم الاعتماد');modalClose('');refresh();render('visits')}else toast(d.error)})()">اعتماد من حسابي</button><button class="btn soft" onclick="modal('إدخال رمز الاعتماد','${esc(enterCodeForm(v.id))}')">لدي رمز سري</button></div></div>`;
  }
  function enterCodeForm(visitId) {
    return `<div style="padding:12px"><h3 style="color:#0d312f;margin:0 0 8px">إدخال رمز الاعتماد</h3><p style="color:#60756f;margin:0 0 16px">أدخل الرمز السري المكون من 10 أرقام الذي استلمه العميل.</p><input id="secretCodeInput" type="text" inputmode="numeric" pattern="[0-9]{10}" maxlength="10" placeholder="أدخل الرمز السري" style="width:100%;padding:12px;border:2px solid #c5d9cf;border-radius:8px;font-size:18px;text-align:center;letter-spacing:4px;font-family:monospace;margin-bottom:12px"><div id="codeError" style="color:#c85c59;font-size:13px;margin-bottom:8px"></div><button class="btn-primary" style="width:100%" onclick="verifyAndApproveCode('${visitId}')">تحقق واعتماد</button></div>`;
  }
  async function verifyAndApproveCode(visitId) {
    const code = document.getElementById("secretCodeInput")?.value?.trim();
    const err = document.getElementById("codeError");
    if (!code || code.length !== 10 || !/^\d{10}$/.test(code)) { if(err)err.textContent="الرجاء إدخال 10 أرقام صحيحة"; return; }
    try {
      const r = await fetch("/api/visits/approve-by-code", {method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({visitId, code, userId:session.id})});
      const d = await r.json();
      if (r.ok && d.ok) { toast("تم اعتماد الزيارة بنجاح"); modalClose(""); refresh(); render("visits"); }
      else { if(err)err.textContent=d.error||"الرمز غير صحيح"; }
    } catch { toast("تعذر الاتصال بالخادم"); }
  }
  function rateTechnicianUI(visitId) {
    let starsHtml = "";
    for (let i = 1; i <= 5; i++) starsHtml += `<span class="rate-star" data-star="${i}" style="font-size:36px;cursor:pointer;color:#d4a24e;transition:.2s">☆</span>`;
    return `<div style="padding:12px"><h3 style="color:#0d312f;margin:0 0 8px">تقييم الفني</h3><p style="color:#60756f;margin:0 0 16px">قيم أداء الفني في هذه الزيارة.</p><div id="starRating" style="text-align:center;margin-bottom:12px;direction:ltr">${starsHtml}</div><textarea id="rateNotes" placeholder="ملاحظات إضافية (اختياري)" style="width:100%;padding:10px;border:1px solid #c5d9cf;border-radius:8px;margin-bottom:12px;min-height:60px"></textarea><button class="btn-primary" style="width:100%" onclick="submitRating('${visitId}')">إرسال التقييم</button></div>`;
  }
  async function submitRating(visitId) {
    const starsEls = document.querySelectorAll("#starRating .rate-star");
    let selected = 0;
    starsEls.forEach(el => { if(el.classList.contains("selected")) selected = parseInt(el.dataset.star); });
    if (!selected) { toast("اختر عدد النجوم"); return; }
    const notes = document.getElementById("rateNotes")?.value || "";
    try {
      const r = await fetch("/api/visits/rate", {method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({visitId, stars:selected, notes, userId:session.id})});
      const d = await r.json();
      if (r.ok && d.ok) { toast("تم إرسال التقييم وشكراً"); modalClose(""); refresh(); render("visits"); }
      else toast(d.error || "فشل إرسال التقييم");
    } catch { toast("تعذر الاتصال بالخادم"); }
  }
  // Initialize star rating interaction
  document.addEventListener("mouseover", function(e) {
    const star = e.target.closest(".rate-star");
    if (!star) return;
    const container = star.closest("#starRating");
    if (!container) return;
    const val = parseInt(star.dataset.star);
    container.querySelectorAll(".rate-star").forEach(el => {
      el.textContent = parseInt(el.dataset.star) <= val ? "★" : "☆";
    });
  });
  document.addEventListener("mouseout", function(e) {
    const container = e.target.closest("#starRating");
    if (!container) return;
    container.querySelectorAll(".rate-star").forEach(el => {
      el.textContent = el.classList.contains("selected") ? "★" : "☆";
    });
  });
  document.addEventListener("click", function(e) {
    const star = e.target.closest(".rate-star");
    if (!star) return;
    const container = star.closest("#starRating");
    if (!container) return;
    const val = parseInt(star.dataset.star);
    container.querySelectorAll(".rate-star").forEach(el => {
      el.classList.toggle("selected", parseInt(el.dataset.star) <= val);
      el.textContent = parseInt(el.dataset.star) <= val ? "★" : "☆";
    });
  });
  // Client pending approvals page section
  function clientPendingApprovals() {
    if (session.role !== "client") return "";
    const pending = visits.filter(v => v.status === "بانتظار الاعتماد" && matchClient(v));
    if (!pending.length) return "";
    return `<section class="panel" style="border-right:4px solid #d4a24e"><h3>زيارات بانتظار اعتمادك</h3>${table(["الرقم","الموعد","الفني","الإجراء"],pending.map(v=>[v.id,fmtDate(v.scheduledAt),v.assignedName||"",`<button class="btn-primary" onclick="approveVisitAsClient('${v.id}')">اعتماد</button>`]))}</section>`;
  }
    // WhatsApp settings page
  function whatsappPage() {
    const c = $("#dashboardContent");
    const checkStatus = async () => {
      try {
        const r = await fetch("/api/whatsapp/status");
        const d = await r.json();
        let html = head("إعدادات واتساب","ربط الإشعارات بالواتساب لإرسال التنبيهات للعملاء والفنيين")+
          `<section class="panel"><h3>حالة الاتصال</h3><div style="display:flex;align-items:center;gap:12px;padding:8px 0"><span class="badge ${d.configured?"success":"pending"}" style="font-size:14px">${d.configured?"مُفعّل":"غير مُفعّل"}</span><span style="color:#60756f">${d.message}</span></div></section>`+
          `<section class="panel"><h3>رقم الجوال للإشعارات</h3><p style="color:#60756f;margin:0 0 12px">أدخل رقم جوالك لاستقبال إشعارات واتساب.</p><div style="display:flex;gap:8px;flex-wrap:wrap"><input id="waPhoneInput" type="tel" inputmode="numeric" placeholder="05xxxxxxxx" value="${esc((users.find(u=>cleanId(u.id)===cleanId(session.id))?.phone||""))}" style="flex:1;min-width:200px;padding:10px;border:1px solid #c5d9cf;border-radius:8px"><label style="display:flex;align-items:center;gap:6px;cursor:pointer"><input type="checkbox" id="waEnabledCheck" ${users.find(u=>cleanId(u.id)===cleanId(session.id))?.whatsappEnabled?"checked":""}> <span style="font-size:13px">تفعيل الإشعارات</span></label><button class="btn-primary" onclick="savePhone()">حفظ</button></div><div id="waSaveMsg" style="margin-top:8px;font-size:13px"></div></section>`+
          `<section class="panel"><h3>تعليمات التفعيل</h3><ol style="line-height:2;padding-right:20px"><li>اشترك مع مزود خدمة واتساب API (مثل: 4jawaly، Twilio، Wapii).</li><li>أضف الرابط والمفتاح في ملف <code>.env</code> على السيرفر:</li></ol><pre style="background:#f0f4f8;padding:12px;border-radius:8px;direction:ltr;text-align:left;font-size:12px;overflow-x:auto;margin-top:8px">WHATSAPP_API_URL=https://api.example.com/send-message\nWHATSAPP_API_KEY=your_api_key_here\nWHATSAPP_SENDER=966xxxxxxxxx</pre><p style="color:#60756f;font-size:12px;margin-top:8px">بعد إعادة تشغيل السيرفر، ستعمل الإشعارات تلقائيًا.</p></section>`+
          `<section class="panel"><h3>سجل الإرسال</h3><div id="waLogPanel">جاري التحميل...</div></section>`;
        c.innerHTML = html;
        // Load WhatsApp-sent notifications
        fetch(`/api/notifications?userId=${encodeURIComponent(session.id)}&role=${encodeURIComponent(session.role)}`,{cache:"no-store"})
          .then(r=>r.json()).then(data=>{
            const waNotifs = (data.notifications||[]).filter(n => n.whatsapp?.sent);
            const rows = waNotifs.map(n => [n.title, n.body||"—", fmtDate(n.createdAt), n.whatsapp?.sent ? `<span class="badge success">✓ أرسل</span>` : `<span class="badge pending">✗ فشل</span>`, n.whatsapp?.to||""]);
            document.getElementById("waLogPanel").innerHTML = rows.length ? table(["العنوان","الرسالة","التاريخ","الحالة","الرقم"],rows) : empty("لا توجد رسائل واتساب","سيظهر هنا سجل الرسائل المرسلة عبر واتساب.");
          }).catch(() => document.getElementById("waLogPanel").innerHTML = "تعذر تحميل السجل.");
      } catch { c.innerHTML = empty("تعذر الاتصال","تأكد من اتصال السيرفر."); }
    };
    checkStatus();
  }
  window.savePhone = async function() {
    const phone = document.getElementById("waPhoneInput")?.value?.replace(/\D/g,"").slice(0,15) || "";
    const enabled = document.getElementById("waEnabledCheck")?.checked || false;
    const msg = document.getElementById("waSaveMsg");
    if (!phone) { msg.textContent = "الرجاء إدخال رقم الجوال"; msg.style.color = "#c85c59"; return; }
    try {
      const r = await fetch("/api/user/phone", {method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({userId:session.id, phone, whatsappEnabled: enabled})});
      const d = await r.json();
      if (r.ok && d.ok) { msg.innerHTML = "✅ تم حفظ رقم الجوال"; msg.style.color = "#3c8b70"; }
      else msg.textContent = d.error || "فشل الحفظ";
    } catch { msg.textContent = "تعذر الاتصال بالخادم"; msg.style.color = "#c85c59"; }
  };
  // ===== End Visit Approval & Rating System =====
  function injectAiModelControls(){
    var chat=document.querySelector(".ai-unified-panel .voice-chat-container");
    if(!chat||document.getElementById("aiModelControls"))return;
    chat.insertAdjacentHTML("beforebegin",'<div id="aiModelControls" class="ai-model-controls"><label>وضع نموذج الخدمة<select id="aiServiceMode" class="field"><option value="customer">موظف خدمة عميل</option><option value="operations">موظف عمليات</option><option value="technical">مساعد فني</option><option value="voice">رد صوتي سريع</option></select></label><label>اختبار التعلم اللغوي<input id="aiLearningProbe" class="field" placeholder="اكتب عبارة لاختبار تنويع الردود"></label><button class="action-btn primary" type="button" data-ai-learning-test>اختبار النموذج المتطور</button><button class="action-btn" type="button" data-ai-feedback="good">الرد ممتاز</button><button class="action-btn" type="button" data-ai-feedback="repeated">الرد مكرر</button><button class="action-btn" type="button" data-ai-feedback="customer-tone">حسّن أسلوب خدمة العميل</button><div id="aiLearningVisibleStatus" class="ai-learning-visible">جاري قراءة حالة التعلم العميق...</div></div>');
    refreshAiLearningVisibleStatus();
  }
  function refreshAiLearningVisibleStatus(){
    var box=document.getElementById("aiLearningVisibleStatus");if(!box)return;
    fetch(`/api/ai/agent/status?userId=${encodeURIComponent(session.id)}&role=${encodeURIComponent(session.role)}`,{cache:"no-store"}).then(r=>r.json()).then(d=>{
      var l=d.linguisticLearning||{},sig=l.learnedSignals||{},recent=d.recentMemory||[];
      box.dataset.latestMemoryId=recent[0]?.id||"";
      box.innerHTML=`<b>نموذج التعلم اللغوي: ${esc(l.persona||"service_employee")}</b><span>النبرة: ${esc(l.tone||"professional")} · الثقة: ${Math.round((l.confidence||0)*100)}% · ذاكرة الردود: ${sig.memorySamples||0}</span><small>يستخدم هذا النموذج لتنويع الردود والعمل كموظف ذكاء اصطناعي حسب دور المستخدم.</small>`;
    }).catch(()=>{box.textContent="تعذر تحميل حالة التعلم العميق."});
  }
  window.sendAiResponseFeedback=function(value){
    var box=document.getElementById("aiLearningVisibleStatus"),id=box?.dataset.latestMemoryId||"";if(!id){toast("لا يوجد رد محفوظ لتقييمه بعد.");return}
    fetch("/api/ai/response-feedback",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({memoryId:id,rating:value,feedback:value})}).then(r=>r.json()).then(d=>{toast(d.ok?"تم حفظ تقييم الرد في التعلم اللغوي":"تعذر حفظ التقييم");refreshAiLearningVisibleStatus()}).catch(()=>toast("تعذر إرسال تقييم الرد"));
  };
  document.addEventListener("click",function(e){var fb=e.target.closest("[data-ai-feedback]");if(fb){sendAiResponseFeedback(fb.dataset.aiFeedback);return}var test=e.target.closest("[data-ai-learning-test]");if(test){var q=document.getElementById("aiLearningProbe")?.value||"اختبر التعلم العميق في الردود كموظف خدمة عملاء";runUnifiedAiCommand(q)}});
  new MutationObserver(injectAiModelControls).observe(document.body,{childList:true,subtree:true});
  setTimeout(injectAiModelControls,0);
  setInterval(function(){if(document.getElementById("aiModelControls"))refreshAiLearningVisibleStatus()},15000);
  function voiceFastClientText(text){var t=String(text||"").replace(/\[EXECUTE:[\s\S]*?\]/g," ").replace(/https?:\/\/\S+/g," ").replace(/<[^>]+>/g," ").replace(/\s+/g," ").trim();if(t.length<=420)return t;var parts=t.split(/(?<=[.!؟?])\s+/),out="";for(var i=0;i<parts.length;i++){if((out+" "+parts[i]).trim().length>420)break;out=(out+" "+parts[i]).trim()}return out||t.slice(0,420)}
  var __speakArabicBase=speakArabic;speakArabic=function(text){return __speakArabicBase(voiceFastClientText(text))};
  var __runUnifiedAiCommandBase=runUnifiedAiCommand;runUnifiedAiCommand=async function(text){var d=await __runUnifiedAiCommandBase(text);var p=d&&d.linguisticProfile;if(p){var box=document.getElementById("aiAnswer");if(box)box.insertAdjacentHTML("beforeend",`<div class="ai-learning-visible"><b>تمت الصياغة عبر نموذج التعلم اللغوي</b><span>${esc(p.persona||"service_employee")} · ${esc(p.tone||"professional")} · ثقة ${Math.round((p.confidence||0)*100)}%</span></div>`)}refreshAiLearningVisibleStatus();return d};
