  function enhancePdfLetterheadButtons(){
    document.querySelectorAll('[data-pdf-doc][data-pdf-clean="true"]:not([data-letterhead-ready])').forEach(function(btn){
      btn.setAttribute('data-letterhead-ready','1');
      var type=btn.dataset.pdfDoc,id=btn.dataset.pdfId;
      if(!type||!id)return;
      if(btn.parentElement&&btn.parentElement.querySelector('[data-pdf-letterhead="true"][data-pdf-doc="'+type+'"][data-pdf-id="'+id+'"]'))return;
      btn.insertAdjacentHTML('afterend',` <button class="${btn.className||'action-btn'}" data-pdf-doc="${type}" data-pdf-id="${id}" data-pdf-letterhead="true">على مطبوعات الشركة</button>`);
    });
  }
  new MutationObserver(enhancePdfLetterheadButtons).observe(document.body,{childList:true,subtree:true});
